    // Dijkstra from every node is appropriate here.

    const INF = Number.MAX_SAFE_INTEGER;

    // Adjacency list for empty travel (cost_i)
    const adjEmpty = Array(n).fill(0).map(() => []);
    for (const [u, v, cost, tax] of roads) {
