        this._comparator = comparator;
    }

    size() {
        return this._heap.length;
    }

    isEmpty() {
        return this.size() === 0;
    }

    peek() {
        return this._heap[0];
    }

    enqueue(element) {
        this._heap.push(element);
        this._siftUp();
    }

    dequeue() {
        if (this.isEmpty()) return undefined;
        if (this.size() === 1) return this._heap.pop();
        const poppedValue = this._heap[0];
        this._heap[0] = this._heap.pop();
        this._siftDown();
        return poppedValue;
    }

    _parent(i) {
        return Math.floor((i - 1) / 2);
    }

    _leftChild(i) {
        return 2 * i + 1;
    }

    _rightChild(i) {
        return 2 * i + 2;
    }

    _swap(i, j) {
        [this._heap[i], this._heap[j]] = [this._heap[j], this._heap[i]];
    }

    _compare(i, j) {
        // Returns true if element i has higher priority than element j
        return this._comparator(this._heap[i], this._heap[j]);
    }

    _siftUp() {
        let nodeIdx = this.size() - 1;
        while (nodeIdx > 0 && this._compare(nodeIdx, this._parent(nodeIdx))) {
            this._swap(nodeIdx, this._parent(nodeIdx));
            nodeIdx = this._parent(nodeIdx);
        }
    }

    _siftDown() {
        let nodeIdx = 0;
        while (
            (this._leftChild(nodeIdx) < this.size() && this._compare(this._leftChild(nodeIdx), nodeIdx)) ||
            (this._rightChild(nodeIdx) < this.size() && this._compare(this._rightChild(nodeIdx), nodeIdx))
        ) {
            const greaterChildIdx = (this._rightChild(nodeIdx) < this.size() && this._compare(this._rightChild(nodeIdx), this._leftChild(nodeIdx)))
                ? this._rightChild(nodeIdx)
                : this._leftChild(nodeIdx);

            this._swap(nodeIdx, greaterChildIdx);
            nodeIdx = greaterChildIdx;
        }
    }
