            const { node: u, cost: d } = pq.dequeue();

            if (d > dist_empty[start_node][u]) continue;

            for (const edge of graph_empty[u]) {
                const v = edge.v;
                const weight = edge.weight;
                if (dist_empty[start_node][u] + weight < dist_empty[start_node][v]) {
                    dist_empty[start_node][v] = dist_empty[start_node][u] + weight;
                    pq.enqueue({ node: v, cost: dist_empty[start_node][v] });
                }
            }
        }
    }

    // --- Shortest path for Carrying Apples (Cost = cost * tax) ---
    // dist_tax[i][j] = shortest path cost from i to j while carrying apples.
    const dist_tax = Array(n).fill(0).map(() => Array(n).fill(Infinity));

    // Run Dijkstra from every node i using the tax weights
    for (let start_node = 0; start_node < n; start_node++) {
        dist_tax[start_node][start_node] = 0;
        const pq = new PriorityQueue((a, b) => a.cost < b.cost); // Min-heap on cost
        pq.enqueue({ node: start_node, cost: 0 });

        while (!pq.isEmpty()) {
            const { node: u, cost: d } = pq.dequeue();

            if (d > dist_tax[start_node][u]) continue;

            for (const edge of graph_tax[u]) {
                const v = edge.v;
                const weight = edge.weight;
                if (dist_tax[start_node][u] + weight < dist_tax[start_node][v]) {
                    dist_tax[start_node][v] = dist_tax[start_node][u] + weight;
                    pq.enqueue({ node: v, cost: dist_tax[start_node][v] });
                }
            }
        }
    }


    // Step 2: Calculate the minimum cost for each store i
    const ans = Array(n).fill(0);

    for (let i = 0; i < n; i++) {
        // Option 1: Buy directly at store i
        let min_cost = prices[i];

        // Option 2: Buy at some store j (j != i) and transport back to i
        // Total Cost = Cost(i -> j, Empty) + Price[j] + Cost(j -> i, Taxed)
        for (let j = 0; j < n; j++) {
            if (i === j) continue;

            const cost_to_j = dist_empty[i][j];
            const cost_back_to_i = dist_tax[j][i];

            // If either path is unreachable, skip
            if (cost_to_j === Infinity || cost_back_to_i === Infinity) {
                continue;
            }

            // Note: Prices can be up to 10^9, path costs up to N * 10^9 * 100 ~ 10^15.
            // JavaScript numbers (IEEE 754 double precision) can safely represent integers up to 2^53 - 1 (~9 * 10^15).
            // Since N <= 1000, Max cost ~ 1000 * 10^9 * 100 = 10^14. This fits safely within standard JS number type.

            const total_cost = cost_to_j + prices[j] + cost_back_to_i;
            if (total_cost < min_cost) {
                min_cost = total_cost;
            }
        }
        ans[i] = min_cost;
    }

    return ans;
}

// --- Helper Class for Priority Queue (Min-Heap) ---
class PriorityQueue {
    constructor(comparator = (a, b) => a < b) {
        this._heap = [];
        this._comparator = comparator;
    }

    size() {
        return this._heap.length;
    }

    isEmpty() {
        return this.size() === 0;
    }

    peek() {
        return this._heap[0];
    }

    enqueue(element) {
        this._heap.push(element);
        this._siftUp();
    }

    dequeue() {
        if (this.isEmpty()) return undefined;
        if (this.size() === 1) return this._heap.pop();
        const poppedValue = this._heap[0];
        this._heap[0] = this._heap.pop();
        this._siftDown();
        return poppedValue;
    }

    _parent(i) {
        return Math.floor((i - 1) / 2);
    }

    _leftChild(i) {
        return 2 * i + 1;
    }

    _rightChild(i) {
        return 2 * i + 2;
    }

    _swap(i, j) {
        [this._heap[i], this._heap[j]] = [this._heap[j], this._heap[i]];
    }

    _compare(i, j) {
        // Returns true if element i has higher priority than element j
        return this._comparator(this._heap[i], this._heap[j]);
    }

    _siftUp() {
        let nodeIdx = this.size() - 1;
        while (nodeIdx > 0 && this._compare(nodeIdx, this._parent(nodeIdx))) {
            this._swap(nodeIdx, this._parent(nodeIdx));
            nodeIdx = this._parent(nodeIdx);
        }
    }

    _siftDown() {
        let nodeIdx = 0;
        while (
            (this._leftChild(nodeIdx) < this.size() && this._compare(this._leftChild(nodeIdx), nodeIdx)) ||
            (this._rightChild(nodeIdx) < this.size() && this._compare(this._rightChild(nodeIdx), nodeIdx))
        ) {
            const greaterChildIdx = (this._rightChild(nodeIdx) < this.size() && this._compare(this._rightChild(nodeIdx), this._leftChild(nodeIdx)))
                ? this._rightChild(nodeIdx)
                : this._leftChild(nodeIdx);

            this._swap(nodeIdx, greaterChildIdx);
            nodeIdx = greaterChildIdx;
        }
    }
}
